#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    if(!(cin >> n)) return 0;
    vector<int> arr(n);
    for(int i = 0; i < n; i++) cin >> arr[i];
    int X; cin >> X;
    int left = 0, right = n - 1;
    while(left <= right){
        int mid = left + (right - left) / 2;
        if(arr[mid] == X){
            cout << mid << endl;
            return 0;
        }
        else if(arr[mid] < X){
            left = mid + 1;
        }
        else{
            right = mid - 1;
        }
    }
    cout << -1 << endl;
    return 0;
}
